features.snippet:
reg [DATAWIDTH-1:0] data [DATADEPTH-1:0];
generate genvar i;
for (i = 0; i < DATADEPTH; i=i+1) begin
always @(posedge CLK)
begin
if (i == 0) data[i] <= SI[i];
else data[i] <= data[i-1];
end
end endgenerate

input [SELWIDTH-1:0] SEL;
reg [DATAWIDTH-1:0] data [DATADEPTH-1:0];
assign DO = data[SEL];

always @(posedge CLK)
begin
if (i == 0)
data[i] <= SI[i];
else
data[i] <= data[i-1];
end
